35: public class KTableFilter<KIn, VIn> implements KTableProcessorSupplier<KIn, VIn, KIn, VIn> {
36:     private final KTableImpl<KIn, ?, VIn> parent;
37:     private final Predicate<? super KIn, ? super VIn> predicate;
38:     private final boolean filterNot;
39:     private final String queryableName;
40:     private boolean sendOldValues;
41:     private boolean useVersionedSemantics = false;
42:     private final StoreFactory storeFactory;
43: 
44:     KTableFilter(final KTableImpl<KIn, ?, VIn> parent,
45:                  final Predicate<? super KIn, ? super VIn> predicate,
46:                  final boolean filterNot,
47:                  final String queryableName,
48:                  final StoreFactory storeFactory) {
49:         this.parent = parent;
50:         this.predicate = predicate;
51:         this.filterNot = filterNot;
52:         this.queryableName = queryableName;
53:         // If upstream is already materialized, enable sending old values to avoid sending unnecessary tombstones:
54:         this.sendOldValues = parent.enableSendingOldValues(false);
55:         this.storeFactory = storeFactory;
56:     }
57: 
58:     public void setUseVersionedSemantics(final boolean useVersionedSemantics) {
59:         this.useVersionedSemantics = useVersionedSemantics;
60:     }
61: 
62:     // VisibleForTesting
63:     boolean isUseVersionedSemantics() {
64:         return useVersionedSemantics;
65:     }
66: 
67:     @Override
68:     public Processor<KIn, Change<VIn>, KIn, Change<VIn>> get() {
69:         return new KTableFilterProcessor();
70:     }
71: 
72:     @Override
73:     public Set<StoreBuilder<?>> stores() {
74:         if (storeFactory == null) {
75:             return null;
76:         }
77:         return Collections.singleton(new StoreFactory.FactoryWrappingStoreBuilder<>(storeFactory));
78:     }
79: 
80:     @Override
81:     public boolean enableSendingOldValues(final boolean forceMaterialization) {
82:         if (queryableName != null) {
83:             sendOldValues = true;
84:             return true;
85:         }
86: 
87:         if (parent.enableSendingOldValues(forceMaterialization)) {
88:             sendOldValues = true;
89:         }
90:         return sendOldValues;
91:     }
92: 
93:     private VIn computeValue(final KIn key, final VIn value) {
94:         VIn newValue = null;
95: 
96:         if (value != null && (filterNot ^ predicate.test(key, value))) {
97:             newValue = value;
98:         }
99: 
100:         return newValue;
101:     }
102: 
103:     private ValueAndTimestamp<VIn> computeValue(final KIn key, final ValueAndTimestamp<VIn> valueAndTimestamp) {
104:         ValueAndTimestamp<VIn> newValueAndTimestamp = null;
105: 
106:         if (valueAndTimestamp != null) {
107:             final VIn value = valueAndTimestamp.value();
108:             if (filterNot ^ predicate.test(key, value)) {
109:                 newValueAndTimestamp = valueAndTimestamp;
110:             }
111:         }
112: 
113:         return newValueAndTimestamp;
114:     }
115: 
116: 
117:     private class KTableFilterProcessor implements Processor<KIn, Change<VIn>, KIn, Change<VIn>> {
118:         private ProcessorContext<KIn, Change<VIn>> context;
119:         private KeyValueStoreWrapper<KIn, VIn> store;
120:         private TimestampedTupleForwarder<KIn, VIn> tupleForwarder;
121: 
122:         @Override
123:         public void init(final ProcessorContext<KIn, Change<VIn>> context) {
124:             this.context = context;
125:             if (queryableName != null) {
126:                 store = new KeyValueStoreWrapper<>(context, queryableName);
127:                 tupleForwarder = new TimestampedTupleForwarder<>(
128:                     store.store(),
129:                     context,
130:                     new TimestampedCacheFlushListener<>(context),
131:                     sendOldValues);
132:             }
133:         }
134: 
135:         @Override
136:         public void process(final Record<KIn, Change<VIn>> record) {
137:             final KIn key = record.key();
138:             final Change<VIn> change = record.value();
139: 
140:             final VIn newValue = computeValue(key, change.newValue);
141:             final VIn oldValue = computeOldValue(key, change);
142: 
143:             if (!useVersionedSemantics) {
144:                 if (sendOldValues && oldValue == null && newValue == null) {
145:                     return; // unnecessary to forward here.
146:                 }
147:             }
148: 
149:             if (queryableName != null) {
150:                 final long putReturnCode = store.put(key, newValue, record.timestamp());
151:                 // if not put to store, do not forward downstream either
152:                 if (putReturnCode != PUT_RETURN_CODE_NOT_PUT) {
153:                     tupleForwarder.maybeForward(record.withValue(new Change<>(newValue, oldValue, putReturnCode == PUT_RETURN_CODE_IS_LATEST)));
154:                 }
155:             } else {
156:                 context.forward(record.withValue(new Change<>(newValue, oldValue, record.value().isLatest)));
157:             }
158:         }
159: 
160:         private VIn computeOldValue(final KIn key, final Change<VIn> change) {
161:             if (!sendOldValues) {
162:                 return null;
163:             }
164: 
165:             return queryableName != null
166:                 ? getValueOrNull(store.get(key))
167:                 : computeValue(key, change.oldValue);
168:         }
169:     }
170: 
171:     @Override
172:     public KTableValueGetterSupplier<KIn, VIn> view() {
173:         // if the KTable is materialized, use the materialized store to return getter value;
174:         // otherwise rely on the parent getter and apply filter on-the-fly
175:         if (queryableName != null) {
176:             return new KTableMaterializedValueGetterSupplier<>(queryableName);
177:         } else {
178:             return new KTableValueGetterSupplier<>() {
179:                 final KTableValueGetterSupplier<KIn, VIn> parentValueGetterSupplier = parent.valueGetterSupplier();
180: 
181:                 public KTableValueGetter<KIn, VIn> get() {
182:                     return new KTableFilterValueGetter(parentValueGetterSupplier.get());
183:                 }
184: 
185:                 @Override
186:                 public String[] storeNames() {
187:                     return parentValueGetterSupplier.storeNames();
188:                 }
189:             };
190:         }
191:     }
192: 
193: 
194:     private class KTableFilterValueGetter implements KTableValueGetter<KIn, VIn> {
195:         private final KTableValueGetter<KIn, VIn> parentGetter;
196: 
197:         KTableFilterValueGetter(final KTableValueGetter<KIn, VIn> parentGetter) {
198:             this.parentGetter = parentGetter;
199:         }
200: 
201:         @Override
202:         public void init(final ProcessorContext<?, ?> context) {
203:             // This is the old processor context for compatibility with the other KTable processors.
204:             // Once we migrate them all, we can swap this out.
205:             parentGetter.init(context);
206:         }
207: 
208:         @Override
209:         public ValueAndTimestamp<VIn> get(final KIn key) {
210:             return computeValue(key, parentGetter.get(key));
211:         }
212: 
213:         @Override
214:         public ValueAndTimestamp<VIn> get(final KIn key, final long asOfTimestamp) {
215:             return computeValue(key, parentGetter.get(key, asOfTimestamp));
216:         }
217: 
218:         @Override
219:         public boolean isVersioned() {
220:             return parentGetter.isVersioned();
221:         }
222: 
223:         @Override
224:         public void close() {
225:             parentGetter.close();
226:         }
227:     }
228: 
229: }
